import boto3
from botocore.exceptions import ClientError

sns = boto3.client('sns')

def lambda_handler(event, context):
    try:
        topic_arn = event['topicArn']
        message_content = event['messageContent']

        if 'notificationType' in event:
            notification_type = event['notificationType']
            if notification_type == 'email':
                sns.publish(
                    TopicArn=topic_arn,
                    Message=message_content,
                    Subject='Event Notification'
                )
            elif notification_type == 'sms':
                sns.publish(
                    TopicArn=topic_arn,
                    Message=message_content,
                    Subject='Event Notification',
                    MessageStructure='string',
                    PhoneNumber='+1234567890'  # Replace with actual phone number
                )

        else:
            raise Exception('Notification type not specified')

    except ClientError as e:
        if e.response['Error']['Code'] == 'InvalidParameter':
            print(f"Error: Invalid parameter. Topic ARN or message content is missing.")
        elif e.response['Error']['Code'] == 'AccessDeniedException':
            print("Error: Access denied to SNS topic")
        else:
            raise

    except Exception as e:
        print(f"Error: {str(e)}")

    return {
        'statusCode': 200,
        'statusMessage': 'OK'
    }